  ],
  "fields": [
    {
      "name": "company_name",
      "description": "Full legal entity name of the company or fund",
      "type": "string",
      "instructions": "Extract the full legal name of the company or fund. Look for the entity name in document headers, cover pages, or incorporation sections. Return the official legal name, not abbreviations or trade names."
    },
    {
      "name": "irr",
      "description": "Internal Rate of Return as a percentage",
      "type": "number",
      "unit": "%",
      "instructions": "Find the Internal Rate of Return (IRR). Look in financial summaries, performance tables, or return metrics sections. Return as a decimal percentage (e.g. 18.5 for 18.5%). If multiple IRR figures exist (gross vs net), prefer net IRR."
    },
    {
      "name": "fund_size",
      "description": "Total fund size or capital commitment in USD",
      "type": "number",
      "unit": "USD",
      "instructions": "Extract the total fund size or total capital commitment. Look in fund overview, key terms, or summary sections. Return the number in full (e.g. 500000000 for $500M). If a target and hard cap exist, return the target."
    },
    {
      "name": "vintage_year",
      "description": "Year the fund was established or first close occurred",
      "type": "number",
      "instructions": "Find the fund vintage year — the year of first close or establishment. Look in fund overview, key terms, or timeline sections. Return as a 4-digit year (e.g. 2023)."
    },
    {
      "name": "investment_type",
      "description": "The type of investment structure: Fund, Co-investment, or Direct",
      "type": "string",
      "options": ["Fund", "Co-investment", "Direct"],
      "instructions": "Determine the investment type. Check for explicit statement 'Investment Type: Fund/Co-investment/Direct'. Look for fund indicators (pooled vehicle, fund size field), co-investment keywords ('alongside', 'sponsor-led', 'co-invest'), or direct investment keywords ('direct equity', 'primary investment'). Default to 'Fund' if ambiguous. Return exactly one of: Fund, Co-investment, Direct."
    }
  ],
  "query": "Summarize the financial highlights, key risk factors, and investment strategy across these documents",
  "llm_config": {
    "provider": "anthropic",
    "model": "claude-haiku-4-5-20251001"
  }
}

